  const svelteSource: string = "// In your Svelte component:\nimport Table from \"lily-design-system-svelte-headless/components/Table/Table.svelte\";\n\n<Table label=\"Table\">\n  <!-- thead, tbody, tfoot -->\n</Table>\n";
